INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (314, 146111, 13, 681, '群居法则', '我，一个普通的孩子，身体健康笑容灿烂，对生活缺乏起码的热情，总是思考一些不容易有答案的问题然后对生活失去更多的信心。我平静地接受好孩子的教育，在谨慎正统里成长，偶尔低低地抒发一些细脚伶仃的伤悲，始终对一切无能为力。
<br>
<br>于是这个安静、祥和、有音乐如水般流过、失去了黑暗没有星光没有月华没有贞子后遗症的夜里，我决定要写点文字，纪念一些东西，一些被时光像洪水猛兽一样席卷过后剩下的看似实在其实犹如空气般漂浮着抓也抓不住的东西。它们从指缝中溜走，我心里悬得慌。
<br>
<br>这种慌乱总是会让我想起弥和彤，我身边最近的朋友。想起曾经和她们之间突如其来的冷战。那种不由自主的逃避。我不知道我该怎样去面对她们，怎样去化解那道无形的界限。我手足无措地站在那里，像一个人被扔在了空旷旷的舞台上一束光从头顶打下来。于是我小心翼翼地避开，对于我无能为力的东西我总是绕道而行，像一尾探出水面的鱼在惊恐中缩回水里。我有很少的朋友，而没有一个人看到过我的全部。我跟一个朋友这么说。其实我不是怕朋友少。那么你在怕什么，也许你只是怕某天醒来后突然发现所有的人都生活在你的心外面。也许，我点点头。生命中不可承受之重不仅存在，而且一抓一大把。
<br>
<br>每个晚上我都坐在书桌前，抬起头看玻璃里映出的另一个自己，我用文字构筑着那个孩子的灵魂。我总是会在长时间的注视后看见一张淡漠的脸在云雾里隐现，眸子深处是未尽的灵机，斜眼低视着芸芸众生，眼底却不见慈悲不见安怀不见伤叹，只遥远地万水千山外晃动着一个似有似无的“空”。我看着他一缕魂魄地随风去了，淡化在漫舞的飞天里。清醒时我明白他是壁画《夜半逾城》中的释迦牟尼。我冷冷地笑，牵动嘴角。然后习惯性地伸手摸摸我的腿。那里有一个伤口。某天它从我体内的某个角落里蹦了出来，在我腿上生根发芽。我拒绝包扎正如我拒绝说话。看着它我感觉清醒，我的身体终于有了缺口，我看见那里有东西流逝有东西死亡。我感觉前所未有的畅快。大概是郁闷得太久了，也麻木地太久了。我想起期末考试期间我和彤每天大喊这个世界真是愈来愈可爱了每天都过得好有意义啊。引来旁人侧目，两个疯子。其实很简单，因为每天都可以死好多次，真他妈爽。还记得彤曾信誓旦旦地说，如果我被逮去补课那我以后再也不认识你了。因为那将无声地说明彤在年级后一百名之列了。结果后来她们班主许说要补课的同学自己报名，彤还是乖乖地举起了手。
<br>
<br>我已经很久没有说话了，正正经经地说话。久到我揣测自己是不是有自闭症了。每天茫然无措地继续生活，拒绝做很多事，像个没被照顾好的小孩呆呆地站在鱼一样穿梭不息的人群中，一脸冷漠。看到五叶桔写花泽类的那句“其实自始自终，他的冷漠都是内心孤独的一种表达”时莫名其妙地想哭。我想大概是我太久没接触阳光了，骨子变得脆弱了。
<br>
<br>于是我郑重其事地搬了把椅子坐在阳台里晒太阳，想晒掉身上阴湿的霉气。顺手操起两本书眯着眼看，上帝在天堂里哧哧地发笑。
<br>
<br>余杰可以说余秋雨的文字如厨房般油腻，王朔可以抨击金庸的小说情节重复索然无味，但这些评论掀起轩然大波也是在他们功成名就的时候了。没有哪家媒体会对一个小孩子的一句“某某某算什么东西”而大肆宣扬，亦没有谁会去关注两个无名小卒间的争吵打闹，其区别不过是有的文雅些，有的粗俗些罢了。正所谓“色即是空”世间万物都是虚无，没有什么是不同的。于是我可以摒弃那些崇高低俗鄙陋雅致，平心静气地从Mozart 听到Marilyn Marson听到王菲听到F4，心安理得地从安妮看到阿来看到钱钟书再看到弗洛依德，大俗大雅间跳来跳去没有跨度感。本来上天入地由爱转恨就只有一线隔。古人有云见山是山见水是水的是庸人，见山不是山见水不是水的是俗人，见山又是山见水又是水的才是智者。山山水水纠缠到最后究竟孰是孰非没有定论，只是那条线也跳来跳去不见了踪影。还是佛祖的训诫能指点迷津，“本来无一物，何处惹尘埃”。
<br>
<br>时至今日，西藏、敦煌、罗布泊等曾在我心中象征着古老而神秘的圣地已被人肆意地咀嚼和践踏得支离破碎了。我于是收藏起它们，让它们在黑暗中疗伤，复元，虽满是裂痕却也遥远地模糊了。然后我可以肆无忌惮地说，我将来想要很多很多的钱，然后隐居，在佛罗伦萨开间茶肆，或者在斯堪的那维亚的海边喂养天鹅。有点脑细胞的人都会斥之以鼻不屑一顾，又或者终究会有人对我说，孩子，总有一天你会像我一样生活。语气沧桑，神情淡漠。我会嘿嘿一笑，让他觉得自己很俗气，也终于彻然大悟，快乐的猪和痛苦的苏格拉底是不同的。虽然从前我一直混淆两者的区别并且不可抑制地羡慕前者，然而我也终于明白一只猪不管快乐不快乐都不会明白达达主义和欧&#183;亨利和流行歌曲和一棵大白菜有什么不一样。而更多的时候我们会成为痛苦的猪。
<br>
<br>一切都是假象。坐在公车上我总是很容易就灵魂出窍，因为窗外穿梭不息或激动或冷漠的人群总是给我太多太多关于这个城市的暗示。公车高大的玻璃总是让我觉得自己像是在看一个精致的橱窗，外面的人和物像是精心编排的话剧，一个一个渐次上演。看着他们我总是很难过，这个城市是如此的诡异却又如此的单调，重复的生活让那些匆忙的人陷入一种不易觉察的麻木，没人会思考城市与尘世的区别。窗外路边是各种各样的商店以及里面用一般等价物来购买劳动产品的人，街道边是春深似海的香樟以及从枝叶间摇晃下来的阳光，一瞬间我想到辛酸想到忧伤，觉得自己恶心得像一个中国式的小文人。尽管如此我也只能重复先哲所说的，“生存即苦难，活着即炼狱” 。梦中的梦中，梦中人的梦中，也许一切都只是繁华的布景，可能某一天，人们在布景前所有的蠢动都会突然消失，一夜间繁华落尽，这也不是没有可能。几亿年前猖獗的恐龙也是无声无息地消失掉的，徒剩下庞大静默的骨骼让人唏嘘。也许正是因为这样才会有那么多的人选择朝生暮死放浪形骸，也许大家只是想在死亡之前与尽可能多的人发生尽可能多的关系，然后一起手拉手义无返顾地奔向死亡。是悲哀还是悲壮。释迦牟尼脸上的表情永远慈悲，可千山万水五行三界却还是逃不过一个“空”。  
<br>
<br>我觉得好笑，扯了扯嘴角结果脸上是痛苦的表情。我觉得自己无可避免地重新成为一个恶心的中国的小文人。就像他们乐意称喜剧为“讽刺剧”。他们认为笑要笑出眼泪笑出痛苦才算笑得深刻，可是这违反人的生理本能。郭小橹说：“中国的知识分子天性崇拜苦难鄙夷轻浮。他们认为喜剧的目的必须与喜剧形式的出发点相背离那才是对的。”  
<br>
<br>街上车水马龙，光怪陆离，无穷无尽的广告牌刺得我眼睛隐隐作痛。今天的有点甜，明天的27层净化，一切都给我物质上的直击与精神上的暗示。我想人类建造的庞大的物质文明的确不断削弱人的精神意志。灵魂浸泡其中上下沉浮苟延残喘。几个月前曾喧嚣一时的研究性课题早已没了着落，像个夭折的孩子匆匆来了又去。谁都自顾不暇没空搭理。想想那时我们想标新立异与众不同，现在发现没有必要。曾经我们自豪于自己品位的非主流而嘲笑一切主流的东西，却忽略了这个世界变化得太快，一转眼听死亡摇滚成了时髦。很早就听过伊索寓言中的“一百只鸟有一百零一种落地方式”，现在终于明白。无论高调低调主流另类，怎么活都是活，你拔下一根头发它也是独一无二的，甚至今天的你已不再是昨天的你,因为细胞新陈代谢持续分裂与更新。哪怕再不和谐的旋律，唱到最后暗哑也变作了深情。
<br>
<br>于是我可以看一些比杜拉斯还晦涩得一塌糊涂，比《情人》还要跳来跳去前不着天后不着地的语言，写一些不仅恶心自己而且恶心别人的文字然后贴到BBS看别人吐得一片狼藉心里还畅快淋漓。我可以在网上对着一个ID一直不停地Key in Key in直到那些文字垃圾充斥满他的大脑，也可以一手一本梵高一手一本王朔再摊一本老庄，东瞟瞟西瞅瞅再正色读一读先人的觉悟。我会因为一句话、一幅画或者仅仅是一个标题就买下一本书然后让它和灰尘一起寂寞，也可以在书店最偏僻的角落捧一本英汉辞典看一条条冗长且繁琐的单词串成串从我眼前缓缓流过。我可以在阳光下看鸢尾枯黄看仙人掌死亡然后继续我的素描，可以放震天响的摇滚安静地躺在房间的一角可以抱着一堆枕垫睡觉。不知道这种颠三倒四黑白混乱的生活可以让我支撑多久，反正到头来“生命只是一袭华美的袍，上面爬满了虱子”。
<br>
<br>我们一直很孤独，因为活在一个彻底的骗局之中。有人这样说。内六根，中六识，外六法是人生的游戏，空无一物的世界上人类悄悄涂抹了几千年的媚相。我知道世上本没有什么大不了的规则，只是形成了习惯无法抗拒。我也知道没有不该爱的人，只是缺少正确的方式。而我更知道，游戏，不可以没有规则。活着就是活着，没有所谓的生命的意义。选择任何一个方向，游向的都是同一个宿命。明天的麦子还是会向着太阳愤怒地生长。
<br>
<br>我想一切都很好，而且还会一直好下去。', '我，一个普通的孩子，身体健康笑容灿烂，对生活缺乏起码的热情，总是思考一些不容易有答案的问题然后对生活失去更多的信心。我平静地接受好孩子的教育，在谨慎正统里成长，偶尔低低地抒发一些细脚伶仃的伤悲，始终对一切无能为力。

